from typing import List

class Solution:
    def findAllPeople(self, n: int, meetings: List[List[int]], firstPerson: int) -> List[int]:
        know_secret = {0, firstPerson}
        meetings.sort(key=lambda x: x[2])
        time = -1
        for x, y, t in meetings:
            if t != time:
                know_secret = set(know_secret)
                time = t
            if x in know_secret:
                know_secret.add(y)
            if y in know_secret:
                know_secret.add(x)
        return sorted(list(know_secret))
```
efficiency: HIGH
time complexity: O(m log m + n)
space complexity: O(n + m)
energy implications: LOW
explanation: Sort meetings by time, then iterate through each meeting. If a person in the meeting knows the secret, add the other person to the set of people who know the secret. This approach ensures that all people who know the secret are found in a single pass through the meetings.

